const HTML = "<!DOCTYPE html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1\">\n<title>Liao TV \u2014 Comunidade</title>\n<meta name=\"description\" content=\"Liao TV \u2014 comunidade oficial, chat ao vivo e redes sociais.\">\n\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Baloo+2:wght@500;600;700;800&family=Nunito:wght@400;600;700;800;900&family=JetBrains+Mono:wght@500&display=swap\" rel=\"stylesheet\">\n\n<style>\n:root{\n  --void-0:#0e0a2e; --void-1:#160f3d; --void-2:#1e1550; --void-3:#2a1c6b;\n  --line:#3a2c82; --line-soft:#2a1f66;\n  --ink-0:#fdfaff; --ink-1:#e4defa; --ink-2:#bcb0e8; --ink-3:#9184c9;\n  --sun:#ffb020; --sun-bright:#ffce5c; --coral:#ff5d6c; --sky:#33c6f4; --mint:#3ddc97; --grape:#b06cff;\n  --radius-lg:26px; --radius-md:18px; --radius-sm:12px;\n  --shadow-deep: 0 30px 80px -18px rgba(5,2,20,0.65);\n  --font-display:'Baloo 2', sans-serif; --font-body:'Nunito', sans-serif; --font-mono:'JetBrains Mono', monospace;\n}\n*{margin:0;padding:0;box-sizing:border-box;}\nhtml{scroll-behavior:smooth;}\nbody{\n  background:\n    radial-gradient(1000px 700px at 15% -10%, rgba(255,176,32,0.10), transparent 60%),\n    radial-gradient(1200px 900px at 100% 10%, rgba(176,108,255,0.14), transparent 55%),\n    radial-gradient(800px 600px at 50% 120%, rgba(51,198,244,0.10), transparent 60%),\n    var(--void-0);\n  color:var(--ink-1); font-family:var(--font-body); min-height:100vh; overflow-x:hidden;\n  -webkit-font-smoothing:antialiased; position:relative;\n}\n::selection{ background:var(--sun); color:#2a1400; }\n::-webkit-scrollbar{ width:9px; }\n::-webkit-scrollbar-track{ background:var(--void-0); }\n::-webkit-scrollbar-thumb{ background:var(--line); border-radius:10px; }\n::-webkit-scrollbar-thumb:hover{ background:var(--ink-3); }\na{ color:inherit; text-decoration:none; }\nbutton{ font-family:inherit; }\ninput,textarea,select{ font-family:inherit; }\n:focus-visible{ outline:3px solid var(--sun-bright); outline-offset:2px; border-radius:8px; }\n\n.shell{ position:relative; z-index:1; max-width:1200px; margin:0 auto; padding:20px 20px 40px; }\n\n/* header */\nheader.top{ display:flex; align-items:center; justify-content:space-between; gap:16px; padding-bottom:14px; }\n.brand-chip{ display:flex; align-items:center; gap:12px; cursor:pointer; }\n.brand-chip .b-icon{ width:42px; height:42px; border-radius:50%; background:linear-gradient(145deg,var(--sun-bright),var(--coral)); display:flex; align-items:center; justify-content:center; font-family:var(--font-display); font-weight:800; color:#2a1400; font-size:18px; }\n.brand-chip .b-name{ font-family:var(--font-display); font-weight:700; font-size:18px; color:var(--ink-0); line-height:1; }\n.brand-chip .b-name span{ color:var(--sun-bright); }\n.brand-chip .b-tag{ font-size:10px; color:var(--ink-3); text-transform:uppercase; letter-spacing:0.08em; margin-top:4px; font-family:var(--font-mono); }\n\n.top-actions{ display:flex; align-items:center; gap:10px; }\n.btn{ font-family:var(--font-display); font-weight:700; font-size:14px; padding:11px 20px; border-radius:14px; border:2px solid transparent; cursor:pointer; display:inline-flex; align-items:center; gap:8px; transition:transform .15s ease, box-shadow .15s ease; }\n.btn:active{ transform:scale(0.96); }\n.btn-primary{ background:linear-gradient(180deg,var(--sun-bright),var(--sun)); color:#2a1400; box-shadow:0 12px 28px -10px rgba(255,176,32,0.5); }\n.btn-primary:hover{ transform:translateY(-2px); }\n.btn-ghost{ background:var(--void-2); border-color:var(--line); color:var(--ink-0); }\n.btn-ghost:hover{ border-color:var(--sun); color:var(--sun-bright); }\n.btn-sm{ padding:8px 14px; font-size:12.5px; border-radius:11px; }\n\n.nav-avatar{ width:42px; height:42px; border-radius:50%; border:2px solid var(--sun); cursor:pointer; display:none; align-items:center; justify-content:center; font-family:var(--font-display); font-weight:700; color:#fff; overflow:hidden; position:relative; flex-shrink:0; }\n.nav-avatar img{ width:100%; height:100%; object-fit:cover; }\n\n/* av menu dropdown */\n.av-wrap{ position:relative; }\n.av-menu{ display:none; position:absolute; top:52px; right:0; background:var(--void-1); border:1px solid var(--line); border-radius:16px; box-shadow:var(--shadow-deep); min-width:190px; z-index:300; overflow:hidden; }\n.av-menu.open{ display:block; }\n.av-menu-item{ display:flex; align-items:center; gap:10px; padding:13px 16px; font-size:13.5px; font-weight:700; cursor:pointer; transition:background .12s; color:var(--ink-1); border-bottom:1px solid var(--line-soft); }\n.av-menu-item:last-child{ border-bottom:none; }\n.av-menu-item:hover{ background:var(--void-2); }\n.av-menu-item.danger{ color:var(--coral); }\n\n/* admin notice */\n.admin-notice{ margin-top:6px; background:linear-gradient(120deg,var(--void-2),var(--void-3)); border:1px solid var(--line); border-radius:var(--radius-md); padding:14px 18px; display:none; }\n.admin-notice.show{ display:flex; align-items:flex-start; gap:12px; }\n.notice-avatar{ width:38px; height:38px; border-radius:50%; border:2px solid var(--sun); flex-shrink:0; cursor:pointer; }\n.notice-label{ font-family:var(--font-mono); font-size:10px; text-transform:uppercase; letter-spacing:0.06em; color:var(--sun-bright); margin-bottom:3px; }\n.notice-body{ font-size:14px; font-weight:700; color:var(--ink-0); line-height:1.5; }\n\n/* social portals */\nsection.socials{ padding:26px 0 8px; }\n.section-head{ margin-bottom:16px; }\n.section-head h2{ font-family:var(--font-display); font-size:18px; color:var(--ink-0); font-weight:700; }\n.section-head p{ margin-top:4px; font-size:13px; color:var(--ink-3); font-weight:600; }\n\n.portal-grid{ display:grid; grid-template-columns:repeat(5,1fr); gap:14px; }\n@media (max-width:920px){ .portal-grid{ grid-template-columns:repeat(3,1fr); } }\n@media (max-width:600px){ .portal-grid{ grid-template-columns:repeat(2,1fr); } }\n\n.portal-card{ position:relative; background:var(--void-2); border:1px solid var(--line-soft); border-radius:var(--radius-md); padding:20px 14px 16px; display:flex; flex-direction:column; align-items:center; gap:10px; text-align:center; transition:transform .2s ease, border-color .2s ease; overflow:hidden; }\n.portal-card:hover{ transform:translateY(-4px); border-color:var(--line); }\n.portal-icon-wrap{ width:50px; height:50px; border-radius:15px; display:flex; align-items:center; justify-content:center; background:rgba(255,255,255,0.07); border:1.5px solid var(--line); }\n.portal-icon-wrap svg{ width:30px; height:30px; }\n.portal-name{ font-family:var(--font-display); font-weight:700; font-size:14px; color:var(--ink-0); }\n.portal-handle{ font-family:var(--font-mono); font-size:11px; font-weight:600; color:var(--ink-2); }\n.portal-card.empty{ opacity:0.75; }\n\n/* CHAT GLOBAL */\nsection.chat-section{ padding:24px 0 10px; }\n.chat-shell{ background:var(--void-1); border:1px solid var(--line-soft); border-radius:var(--radius-lg); box-shadow:var(--shadow-deep); display:flex; flex-direction:column; height:min(72vh, 680px); overflow:hidden; }\n.chat-head{ display:flex; align-items:center; justify-content:space-between; padding:16px 20px; border-bottom:1px solid var(--line-soft); flex-shrink:0; }\n.chat-head h2{ font-family:var(--font-display); font-size:16px; color:var(--ink-0); display:flex; align-items:center; gap:8px; }\n.chat-live-dot{ width:8px; height:8px; border-radius:50%; background:var(--mint); box-shadow:0 0 0 0 rgba(61,220,151,.6); animation:livePulse 1.8s infinite; }\n@keyframes livePulse{ 0%{box-shadow:0 0 0 0 rgba(61,220,151,.55);} 70%{box-shadow:0 0 0 8px rgba(61,220,151,0);} 100%{box-shadow:0 0 0 0 rgba(61,220,151,0);} }\n.chat-count{ font-family:var(--font-mono); font-size:11px; color:var(--ink-3); }\n\n.chat-list{ flex:1; overflow-y:auto; padding:14px 16px; display:flex; flex-direction:column; gap:2px; }\n.chat-empty{ text-align:center; padding:40px 0; color:var(--ink-3); font-size:13.5px; font-weight:600; }\n\n.msg{ display:flex; gap:10px; padding:8px 8px; border-radius:14px; transition:background .15s ease; position:relative; animation:msgIn .28s cubic-bezier(.2,.8,.2,1); }\n.msg:hover{ background:rgba(255,255,255,0.03); }\n@keyframes msgIn{ from{ opacity:0; transform:translateY(10px); } to{ opacity:1; transform:translateY(0); } }\n.msg-av{ width:36px; height:36px; border-radius:50%; flex-shrink:0; display:flex; align-items:center; justify-content:center; font-family:var(--font-display); font-weight:700; color:#fff; overflow:hidden; cursor:pointer; font-size:14px; }\n.msg-av img{ width:100%; height:100%; object-fit:cover; }\n.msg-body{ flex:1; min-width:0; }\n.msg-top{ display:flex; align-items:baseline; gap:6px; flex-wrap:wrap; }\n.msg-name{ font-family:var(--font-display); font-weight:700; font-size:13.5px; color:var(--ink-0); cursor:pointer; }\n.msg-name:hover{ color:var(--sun-bright); }\n.msg-time{ font-family:var(--font-mono); font-size:10.5px; color:var(--ink-3); }\n.msg-verified{ display:inline-flex; width:13px; height:13px; border-radius:50%; background:var(--sky); align-items:center; justify-content:center; flex-shrink:0; }\n.msg-verified svg{ width:8px; height:8px; }\n.msg-vip{ font-size:10px; font-weight:800; color:var(--sun); background:rgba(255,176,32,0.14); border:1px solid rgba(255,176,32,0.3); padding:1px 6px; border-radius:999px; }\n.msg-text{ font-size:14px; color:var(--ink-1); font-weight:600; line-height:1.5; margin-top:2px; word-break:break-word; }\n.msg-text .mention{ color:var(--sky); font-weight:800; }\n.msg-gif{ margin-top:6px; max-width:220px; border-radius:14px; overflow:hidden; border:1px solid var(--line-soft); display:block; }\n.msg-gif img{ width:100%; display:block; }\n\n.msg-reactions{ display:flex; gap:5px; flex-wrap:wrap; margin-top:6px; }\n.reaction-pill{ display:flex; align-items:center; gap:4px; background:var(--void-2); border:1px solid var(--line-soft); border-radius:999px; padding:3px 9px; font-size:12px; cursor:pointer; transition:all .15s ease; }\n.reaction-pill:hover{ border-color:var(--sun); }\n.reaction-pill.mine{ border-color:var(--sun); background:rgba(255,176,32,0.12); }\n.reaction-pill .rc-count{ font-family:var(--font-mono); font-size:10.5px; color:var(--ink-2); font-weight:700; }\n\n/* hold-to-react popover */\n.react-popover{ position:absolute; display:none; background:var(--void-1); border:1px solid var(--line); border-radius:999px; padding:6px 8px; gap:4px; box-shadow:var(--shadow-deep); z-index:50; top:-46px; left:36px; }\n.react-popover.show{ display:flex; animation:popIn .16s ease; }\n@keyframes popIn{ from{ opacity:0; transform:scale(.8) translateY(6px); } to{ opacity:1; transform:scale(1) translateY(0); } }\n.react-emoji{ font-size:19px; cursor:pointer; transition:transform .1s ease; background:none; border:none; padding:4px; border-radius:50%; }\n.react-emoji:hover{ transform:scale(1.25); background:var(--void-2); }\n\n/* compose bar */\n.chat-compose{ border-top:1px solid var(--line-soft); padding:12px 14px; flex-shrink:0; position:relative; }\n.compose-row{ display:flex; align-items:flex-end; gap:8px; }\n.compose-av{ width:34px; height:34px; border-radius:50%; flex-shrink:0; display:flex; align-items:center; justify-content:center; font-family:var(--font-display); font-weight:700; color:#fff; overflow:hidden; font-size:13px; }\n.compose-av img{ width:100%; height:100%; object-fit:cover; }\n.compose-field{ flex:1; display:flex; align-items:center; background:var(--void-2); border:1px solid var(--line-soft); border-radius:20px; padding:4px 6px 4px 16px; gap:4px; }\n.compose-field textarea{ flex:1; background:none; border:none; color:var(--ink-0); font-size:14px; font-weight:600; resize:none; max-height:90px; padding:8px 0; outline:none; }\n.compose-field textarea::placeholder{ color:var(--ink-3); }\n.compose-icon-btn{ width:34px; height:34px; border-radius:50%; background:none; border:none; color:var(--ink-2); display:flex; align-items:center; justify-content:center; cursor:pointer; flex-shrink:0; transition:background .15s ease, color .15s ease; }\n.compose-icon-btn:hover{ background:var(--void-3); color:var(--sun-bright); }\n.compose-icon-btn svg{ width:19px; height:19px; }\n.compose-send{ width:38px; height:38px; border-radius:50%; background:linear-gradient(180deg,var(--sun-bright),var(--sun)); border:none; color:#2a1400; display:flex; align-items:center; justify-content:center; cursor:pointer; flex-shrink:0; }\n.compose-send svg{ width:17px; height:17px; }\n.compose-send:disabled{ opacity:0.4; cursor:default; }\n\n.login-prompt-chat{ display:flex; align-items:center; justify-content:space-between; gap:10px; padding:12px 16px; background:var(--void-2); border-top:1px solid var(--line-soft); }\n.login-prompt-chat span{ font-size:13px; font-weight:700; color:var(--ink-2); }\n\n/* mention dropdown */\n.mention-drop{ display:none; position:absolute; bottom:100%; left:14px; right:14px; background:var(--void-1); border:1px solid var(--line); border-radius:14px; margin-bottom:8px; max-height:220px; overflow-y:auto; box-shadow:var(--shadow-deep); z-index:60; }\n.mention-drop.show{ display:block; }\n.mention-item{ display:flex; align-items:center; gap:10px; padding:10px 14px; cursor:pointer; }\n.mention-item:hover{ background:var(--void-2); }\n.mention-item .mi-av{ width:28px; height:28px; border-radius:50%; display:flex; align-items:center; justify-content:center; font-weight:700; color:#fff; font-size:12px; overflow:hidden; }\n.mention-item .mi-av img{ width:100%; height:100%; object-fit:cover; }\n\n/* GIF picker */\n.gif-picker{ display:none; position:absolute; bottom:100%; left:0; right:0; background:var(--void-1); border:1px solid var(--line); border-radius:18px; margin-bottom:10px; box-shadow:var(--shadow-deep); z-index:70; max-height:340px; display:none; flex-direction:column; }\n.gif-picker.show{ display:flex; }\n.gif-search{ padding:12px; border-bottom:1px solid var(--line-soft); }\n.gif-search input{ width:100%; background:var(--void-2); border:1px solid var(--line-soft); border-radius:12px; padding:10px 14px; color:var(--ink-0); font-size:13.5px; font-weight:600; }\n.gif-grid{ display:grid; grid-template-columns:repeat(3,1fr); gap:6px; padding:10px; overflow-y:auto; }\n.gif-grid img{ width:100%; height:80px; object-fit:cover; border-radius:8px; cursor:pointer; background:var(--void-2); transition:transform .12s ease; }\n.gif-grid img:hover{ transform:scale(1.05); }\n.gif-empty{ text-align:center; padding:30px 0; color:var(--ink-3); font-size:12.5px; grid-column:1/-1; }\n\n/* emoji picker */\n.emoji-picker{ display:none; position:absolute; bottom:100%; right:0; background:var(--void-1); border:1px solid var(--line); border-radius:18px; margin-bottom:10px; box-shadow:var(--shadow-deep); z-index:70; width:280px; max-height:260px; overflow-y:auto; padding:10px; }\n.emoji-picker.show{ display:grid; grid-template-columns:repeat(8,1fr); gap:2px; }\n.emoji-picker button{ background:none; border:none; font-size:19px; padding:6px; border-radius:8px; cursor:pointer; }\n.emoji-picker button:hover{ background:var(--void-2); }\n\n/* footer */\nfooter.site-footer{ margin-top:34px; padding-top:22px; border-top:1px solid var(--line-soft); display:flex; align-items:center; justify-content:space-between; gap:16px; flex-wrap:wrap; }\n.footer-brand{ display:flex; align-items:center; gap:8px; }\n.footer-brand span{ font-family:var(--font-display); font-weight:700; color:var(--ink-2); font-size:13px; }\n.admin-trigger{ font-family:var(--font-mono); font-size:10.5px; color:var(--ink-3); background:transparent; border:1px solid var(--line-soft); padding:6px 13px; border-radius:999px; cursor:pointer; opacity:0.5; }\n.admin-trigger:hover{ opacity:1; color:var(--ink-1); }\n\n/* Modal generic */\n.modal-overlay{ position:fixed; inset:0; z-index:500; background:rgba(6,3,20,0.75); backdrop-filter:blur(6px); display:flex; align-items:center; justify-content:center; padding:18px; opacity:0; pointer-events:none; transition:opacity .25s ease; }\n.modal-overlay.show{ opacity:1; pointer-events:auto; }\n.modal-box{ width:100%; max-width:420px; background:var(--void-1); border:1px solid var(--line); border-radius:var(--radius-lg); padding:28px; box-shadow:var(--shadow-deep); transform:translateY(14px) scale(0.98); transition:transform .25s ease; max-height:88vh; overflow-y:auto; }\n.modal-overlay.show .modal-box{ transform:translateY(0) scale(1); }\n.modal-head{ display:flex; align-items:center; justify-content:space-between; margin-bottom:20px; }\n.modal-head h3{ font-family:var(--font-display); font-size:18px; color:var(--ink-0); }\n.modal-close{ width:30px; height:30px; border-radius:10px; background:var(--void-2); border:1px solid var(--line-soft); display:flex; align-items:center; justify-content:center; cursor:pointer; color:var(--ink-2); }\n.modal-close:hover{ color:var(--ink-0); }\n.field-label{ font-family:var(--font-mono); font-size:10.5px; text-transform:uppercase; letter-spacing:0.05em; color:var(--ink-3); margin-bottom:6px; display:block; }\n.modal-box input[type=\"text\"], .modal-box input[type=\"password\"], .modal-box input[type=\"email\"], .modal-box textarea{\n  width:100%; background:var(--void-2); border:1px solid var(--line-soft); border-radius:12px; padding:12px 14px; color:var(--ink-0); font-weight:700; font-size:14.5px; margin-bottom:14px;\n}\n.modal-box input:focus, .modal-box textarea:focus{ border-color:var(--sun); }\n.modal-error{ font-size:12.5px; color:var(--coral); font-weight:700; margin:-8px 0 14px; display:none; }\n.modal-error.show{ display:block; }\n.modal-switch{ text-align:center; font-size:13px; color:var(--ink-3); font-weight:600; margin-top:4px; }\n.modal-switch a{ color:var(--sun-bright); font-weight:800; cursor:pointer; }\n.email-preview{ font-family:var(--font-mono); font-size:11.5px; color:var(--ink-3); margin:-10px 0 14px; }\n\n.avatar-picker-row{ display:flex; align-items:center; gap:14px; margin-bottom:16px; }\n.avatar-picker-preview{ width:64px; height:64px; border-radius:50%; background:var(--sun); display:flex; align-items:center; justify-content:center; font-family:var(--font-display); font-weight:800; font-size:24px; color:#2a1400; overflow:hidden; flex-shrink:0; }\n.avatar-picker-preview img{ width:100%; height:100%; object-fit:cover; }\n.avatar-upload-btn{ font-size:12.5px; font-weight:800; color:var(--ink-0); background:var(--void-2); border:1px solid var(--line-soft); padding:9px 14px; border-radius:11px; cursor:pointer; }\n\n.letter-color-row{ display:flex; gap:8px; flex-wrap:wrap; margin-bottom:16px; }\n.letter-dot{ width:30px; height:30px; border-radius:50%; cursor:pointer; border:2px solid transparent; transition:transform .12s ease; }\n.letter-dot:hover{ transform:scale(1.12); }\n.letter-dot.active{ border-color:var(--ink-0); }\n\n/* Admin modal (link management) */\n.admin-tabs{ display:flex; gap:6px; background:var(--void-2); border:1px solid var(--line-soft); border-radius:999px; padding:4px; margin-bottom:18px; }\n.admin-tab{ flex:1; background:transparent; border:none; color:var(--ink-3); font-family:var(--font-display); font-weight:700; font-size:13px; padding:9px 0; border-radius:999px; cursor:pointer; }\n.admin-tab.active{ background:var(--void-3); color:var(--ink-0); }\n.admin-panel{ display:none; }\n.admin-panel.show{ display:block; }\n.link-row-list{ display:flex; flex-direction:column; gap:8px; margin-bottom:16px; max-height:200px; overflow-y:auto; }\n.link-row{ display:flex; align-items:center; gap:8px; background:var(--void-2); border:1px solid var(--line-soft); border-radius:10px; padding:8px 11px; }\n.link-row .lr-net{ font-family:var(--font-display); font-weight:700; font-size:12.5px; width:74px; flex-shrink:0; }\n.link-row .lr-url{ font-family:var(--font-mono); font-size:11px; color:var(--ink-3); flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }\n.link-row .lr-del{ width:24px; height:24px; border-radius:8px; background:none; border:none; color:var(--ink-3); cursor:pointer; flex-shrink:0; }\n.link-row .lr-del:hover{ color:var(--coral); }\n.add-link-row{ display:flex; gap:8px; margin-bottom:6px; }\n.add-link-row select{ background:var(--void-2); border:1px solid var(--line-soft); border-radius:10px; padding:10px; color:var(--ink-0); font-weight:700; font-size:12.5px; }\n.add-link-row input{ flex:1; margin-bottom:0 !important; }\n\n/* Profile page */\n.profile-page{ position:fixed; inset:0; z-index:600; background:var(--void-0); display:none; overflow-y:auto; }\n.profile-page.show{ display:block; }\n.profile-top{ position:sticky; top:0; background:rgba(14,10,46,0.9); backdrop-filter:blur(14px); border-bottom:1px solid var(--line-soft); padding:14px 18px; display:flex; align-items:center; gap:14px; z-index:2; }\n.profile-back{ width:36px; height:36px; border-radius:12px; background:var(--void-2); border:1px solid var(--line-soft); display:flex; align-items:center; justify-content:center; cursor:pointer; color:var(--ink-1); }\n.profile-hero{ padding:30px 20px; max-width:640px; margin:0 auto; text-align:center; }\n.profile-avatar-big{ width:96px; height:96px; border-radius:50%; margin:0 auto 14px; border:3px solid var(--sun); display:flex; align-items:center; justify-content:center; font-family:var(--font-display); font-weight:800; font-size:36px; color:#fff; overflow:hidden; }\n.profile-avatar-big img{ width:100%; height:100%; object-fit:cover; }\n.profile-name{ font-family:var(--font-display); font-size:22px; font-weight:700; color:var(--ink-0); display:flex; align-items:center; justify-content:center; gap:6px; }\n.profile-handle{ font-family:var(--font-mono); font-size:13px; color:var(--ink-3); margin-top:4px; }\n.profile-bio{ font-size:14px; color:var(--ink-2); font-weight:600; margin-top:14px; max-width:440px; margin-left:auto; margin-right:auto; line-height:1.6; }\n.profile-stats{ display:flex; justify-content:center; gap:26px; margin-top:18px; }\n.profile-stat b{ display:block; font-family:var(--font-display); font-size:18px; color:var(--ink-0); }\n.profile-stat span{ font-size:11.5px; color:var(--ink-3); font-weight:700; text-transform:uppercase; letter-spacing:0.04em; }\n.profile-actions{ display:flex; justify-content:center; gap:10px; margin-top:20px; }\n.follow-btn{ background:linear-gradient(180deg,var(--sun-bright),var(--sun)); color:#2a1400; }\n.follow-btn.following{ background:var(--void-2); color:var(--ink-0); border-color:var(--line); }\n.profile-join{ font-size:12px; color:var(--ink-3); margin-top:16px; font-weight:600; }\n\n/* toast */\n.toast{ position:fixed; bottom:26px; left:50%; transform:translateX(-50%) translateY(100px); background:var(--void-1); border:1px solid var(--line); color:var(--ink-0); padding:13px 22px; border-radius:14px; font-size:13.5px; font-weight:700; box-shadow:var(--shadow-deep); z-index:900; transition:transform .3s cubic-bezier(.2,.8,.2,1); }\n.toast.show{ transform:translateX(-50%) translateY(0); }\n.toast.err{ border-color:var(--coral); }\n\n@media (max-width:640px){\n  .chat-shell{ height:70vh; }\n  header.top{ flex-wrap:wrap; }\n}\n</style>\n</head>\n<body>\n<div class=\"shell\">\n\n  <header class=\"top\">\n    <div class=\"brand-chip\" onclick=\"window.scrollTo({top:0,behavior:'smooth'})\">\n      <div class=\"b-icon\">L</div>\n      <div>\n        <div class=\"b-name\">Liao<span> TV</span></div>\n        <div class=\"b-tag\">Comunidade oficial</div>\n      </div>\n    </div>\n    <div class=\"top-actions\">\n      <button class=\"btn btn-ghost btn-sm\" id=\"btnLogin\" onclick=\"openLogin()\">Entrar</button>\n      <button class=\"btn btn-primary btn-sm\" id=\"btnReg\" onclick=\"openRegister()\">Criar conta</button>\n      <div class=\"av-wrap\">\n        <div class=\"nav-avatar\" id=\"navAv\" onclick=\"toggleAvMenu(event)\"></div>\n        <div class=\"av-menu\" id=\"avMenu\">\n          <div class=\"av-menu-item\" onclick=\"openProfileSelf()\">\ud83d\udc64 Meu perfil</div>\n          <div class=\"av-menu-item\" onclick=\"openEditProfileModal()\">\u2699\ufe0f Editar perfil</div>\n          <div class=\"av-menu-item danger\" onclick=\"logout()\">\ud83d\udeaa Sair da conta</div>\n        </div>\n      </div>\n    </div>\n  </header>\n\n  <div class=\"admin-notice\" id=\"adminNotice\">\n    <img class=\"notice-avatar\" id=\"noticeAvatarBtn\" onclick=\"openProfile('adm')\" src=\"\" alt=\"ADM\">\n    <div>\n      <div class=\"notice-label\">Aviso da equipe Liao</div>\n      <div class=\"notice-body\" id=\"noticeBodyText\"></div>\n    </div>\n  </div>\n\n  <section class=\"socials\">\n    <div class=\"section-head\">\n      <h2>Redes oficiais</h2>\n      <p>Siga a Liao em todas as plataformas</p>\n    </div>\n    <div class=\"portal-grid\" id=\"portalGrid\"></div>\n  </section>\n\n  <section class=\"chat-section\">\n    <div class=\"section-head\">\n      <h2>Chat global da comunidade</h2>\n      <p>Converse em tempo real com outros f\u00e3s \u2014 todo mundo v\u00ea aqui</p>\n    </div>\n    <div class=\"chat-shell\">\n      <div class=\"chat-head\">\n        <h2><span class=\"chat-live-dot\"></span> Chat ao vivo</h2>\n        <span class=\"chat-count\" id=\"chatCount\">\u2014 mensagens</span>\n      </div>\n      <div class=\"chat-list\" id=\"chatList\">\n        <div class=\"chat-empty\">Carregando o chat...</div>\n      </div>\n      <div id=\"loginPromptChat\" class=\"login-prompt-chat\" style=\"display:none;\">\n        <span>Entre para participar do chat</span>\n        <button class=\"btn btn-primary btn-sm\" onclick=\"openLogin()\">Entrar</button>\n      </div>\n      <div class=\"chat-compose\" id=\"chatCompose\" style=\"display:none;\">\n        <div class=\"mention-drop\" id=\"mentionDrop\"></div>\n        <div class=\"gif-picker\" id=\"gifPicker\">\n          <div class=\"gif-search\"><input type=\"text\" id=\"gifSearchInput\" placeholder=\"Buscar GIFs...\" oninput=\"onGifSearch(this.value)\"></div>\n          <div class=\"gif-grid\" id=\"gifGrid\"></div>\n        </div>\n        <div class=\"emoji-picker\" id=\"emojiPicker\"></div>\n        <div class=\"compose-row\">\n          <div class=\"compose-av\" id=\"composeAv\"></div>\n          <div class=\"compose-field\">\n            <textarea id=\"chatInput\" rows=\"1\" placeholder=\"Diga algo para a comunidade...\" oninput=\"onChatInput(this)\" onkeydown=\"onChatKey(event)\"></textarea>\n            <button class=\"compose-icon-btn\" title=\"Emoji\" onclick=\"toggleEmojiPicker()\">\n              <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M8 14s1.5 2 4 2 4-2 4-2\"/><line x1=\"9\" y1=\"9\" x2=\"9.01\" y2=\"9\"/><line x1=\"15\" y1=\"9\" x2=\"15.01\" y2=\"9\"/></svg>\n            </button>\n            <button class=\"compose-icon-btn\" title=\"GIF\" onclick=\"toggleGifPicker()\">\n              <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"5\" width=\"18\" height=\"14\" rx=\"3\"/><text x=\"12\" y=\"15\" font-size=\"7\" text-anchor=\"middle\" fill=\"currentColor\" stroke=\"none\" font-family=\"monospace\" font-weight=\"700\">GIF</text></svg>\n            </button>\n          </div>\n          <button class=\"compose-send\" id=\"chatSendBtn\" onclick=\"sendChatMessage()\">\n            <svg viewBox=\"0 0 24 24\" fill=\"currentColor\"><path d=\"M2 21l21-9L2 3v7l15 2-15 2v7z\"/></svg>\n          </button>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <footer class=\"site-footer\">\n    <div class=\"footer-brand\">\n      <span>Liao TV \u2014 feito com carinho para a comunidade</span>\n    </div>\n    <button class=\"admin-trigger\" onclick=\"openAdminModal()\">painel adm</button>\n  </footer>\n</div>\n\n<!-- LOGIN MODAL -->\n<div class=\"modal-overlay\" id=\"loginModal\">\n  <div class=\"modal-box\">\n    <div class=\"modal-head\"><h3>Entrar</h3><button class=\"modal-close\" onclick=\"closeModal('loginModal')\">\u2715</button></div>\n    <div class=\"modal-error\" id=\"loginErr\"></div>\n    <label class=\"field-label\">Email ou usu\u00e1rio</label>\n    <input type=\"text\" id=\"liEmail\" placeholder=\"seu.email ou seuemail@...\">\n    <label class=\"field-label\">Senha</label>\n    <input type=\"password\" id=\"liPass\" placeholder=\"\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022\">\n    <button class=\"btn btn-primary\" id=\"loginBtn\" style=\"width:100%;justify-content:center;\" onclick=\"doLogin()\">Entrar</button>\n    <div class=\"modal-switch\">Ainda n\u00e3o tem conta? <a onclick=\"openRegister()\">Criar conta</a></div>\n  </div>\n</div>\n\n<!-- REGISTER MODAL -->\n<div class=\"modal-overlay\" id=\"regModal\">\n  <div class=\"modal-box\">\n    <div class=\"modal-head\"><h3>Criar conta local</h3><button class=\"modal-close\" onclick=\"closeModal('regModal')\">\u2715</button></div>\n    <div class=\"modal-error\" id=\"regErr\"></div>\n\n    <div class=\"avatar-picker-row\">\n      <div class=\"avatar-picker-preview\" id=\"regAvPrev\">C</div>\n      <div>\n        <input type=\"file\" id=\"regAvFile\" accept=\"image/*\" style=\"display:none\" onchange=\"prevAvatar(this,'regAvPrev')\">\n        <button type=\"button\" class=\"avatar-upload-btn\" onclick=\"document.getElementById('regAvFile').click()\">Enviar foto</button>\n      </div>\n    </div>\n    <div class=\"letter-color-row\" id=\"regColorRow\"></div>\n\n    <label class=\"field-label\">Nome de exibi\u00e7\u00e3o</label>\n    <input type=\"text\" id=\"regName\" placeholder=\"Como te chamam\" oninput=\"updateRegInit()\">\n    <label class=\"field-label\">Usu\u00e1rio (@)</label>\n    <input type=\"text\" id=\"regHandle\" placeholder=\"seu_usuario\">\n    <label class=\"field-label\">Email</label>\n    <input type=\"text\" id=\"regEmail\" placeholder=\"voce\" oninput=\"updateEmailPreview()\">\n    <div class=\"email-preview\" id=\"emailPreview\"></div>\n    <label class=\"field-label\">Senha</label>\n    <input type=\"password\" id=\"regPass\" placeholder=\"m\u00ednimo 6 caracteres\">\n    <button class=\"btn btn-primary\" id=\"regBtn\" style=\"width:100%;justify-content:center;\" onclick=\"createAccount()\">Criar conta</button>\n    <div class=\"modal-switch\">J\u00e1 tem conta? <a onclick=\"closeModal('regModal');openLogin()\">Entrar</a></div>\n  </div>\n</div>\n\n<!-- EDIT PROFILE MODAL -->\n<div class=\"modal-overlay\" id=\"editModal\">\n  <div class=\"modal-box\">\n    <div class=\"modal-head\"><h3>Editar perfil</h3><button class=\"modal-close\" onclick=\"closeModal('editModal')\">\u2715</button></div>\n    <div class=\"avatar-picker-row\">\n      <div class=\"avatar-picker-preview\" id=\"editAvPrev\">C</div>\n      <div>\n        <input type=\"file\" id=\"editAvFile\" accept=\"image/*\" style=\"display:none\" onchange=\"prevAvatar(this,'editAvPrev')\">\n        <button type=\"button\" class=\"avatar-upload-btn\" onclick=\"document.getElementById('editAvFile').click()\">Trocar foto</button>\n      </div>\n    </div>\n    <label class=\"field-label\">Nome de exibi\u00e7\u00e3o</label>\n    <input type=\"text\" id=\"editName\">\n    <label class=\"field-label\">Bio</label>\n    <textarea id=\"editDesc\" rows=\"3\" style=\"resize:vertical;\"></textarea>\n    <button class=\"btn btn-primary\" style=\"width:100%;justify-content:center;\" onclick=\"saveProfile()\">Salvar altera\u00e7\u00f5es</button>\n  </div>\n</div>\n\n<!-- ADMIN MODAL -->\n<div class=\"modal-overlay\" id=\"adminModal\">\n  <div class=\"modal-box\">\n    <div class=\"modal-head\"><h3>Painel ADM Liao</h3><button class=\"modal-close\" onclick=\"closeModal('adminModal')\">\u2715</button></div>\n\n    <div id=\"adminLockBody\">\n      <label class=\"field-label\">Senha de administrador</label>\n      <input type=\"password\" id=\"adminPasswordInput\" placeholder=\"\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022\">\n      <div class=\"modal-error\" id=\"adminError\">Senha incorreta.</div>\n      <button class=\"btn btn-primary\" id=\"adminSubmitBtn\" style=\"width:100%;justify-content:center;\">Entrar</button>\n    </div>\n\n    <div id=\"adminPanelBody\" style=\"display:none;\">\n      <div class=\"admin-tabs\">\n        <button class=\"admin-tab active\" id=\"adminTabLinks\">Links sociais</button>\n        <button class=\"admin-tab\" id=\"adminTabNotice\">Aviso</button>\n      </div>\n      <div class=\"admin-panel show\" id=\"adminPanelLinks\">\n        <div class=\"link-row-list\" id=\"linkRowList\"></div>\n        <div class=\"add-link-row\">\n          <select id=\"newLinkNetwork\">\n            <option value=\"TikTok\">TikTok</option>\n            <option value=\"Instagram\">Instagram</option>\n            <option value=\"YouTube\">YouTube</option>\n            <option value=\"Kwai\">Kwai</option>\n            <option value=\"Facebook\">Facebook</option>\n          </select>\n          <input type=\"text\" id=\"newLinkUrl\" placeholder=\"https://...\">\n        </div>\n        <button class=\"btn btn-ghost btn-sm\" style=\"width:100%;justify-content:center;\" id=\"addLinkBtn\">Adicionar / atualizar link</button>\n      </div>\n      <div class=\"admin-panel\" id=\"adminPanelNotice\">\n        <label class=\"field-label\">Mensagem do aviso</label>\n        <textarea id=\"noticeTextarea\" rows=\"3\" style=\"resize:vertical;\"></textarea>\n        <div style=\"display:flex;gap:8px;\">\n          <button class=\"btn btn-primary btn-sm\" style=\"flex:1;justify-content:center;\" id=\"publishNoticeBtn\">Publicar aviso</button>\n          <button class=\"btn btn-ghost btn-sm\" style=\"flex:1;justify-content:center;\" id=\"clearNoticeBtn\">Remover aviso</button>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- PROFILE PAGE -->\n<div class=\"profile-page\" id=\"profilePage\">\n  <div class=\"profile-top\">\n    <div class=\"profile-back\" onclick=\"closeProfile()\">\n      <svg width=\"18\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"m15 18-6-6 6-6\"/></svg>\n    </div>\n    <strong style=\"font-family:var(--font-display);color:var(--ink-0);\">Perfil</strong>\n  </div>\n  <div class=\"profile-hero\">\n    <div class=\"profile-avatar-big\" id=\"profAvatarBig\"></div>\n    <div class=\"profile-name\" id=\"profName\"></div>\n    <div class=\"profile-handle\" id=\"profHandle\"></div>\n    <div class=\"profile-bio\" id=\"profBio\"></div>\n    <div class=\"profile-stats\">\n      <div class=\"profile-stat\"><b id=\"profFollowers\">0</b><span>Seguidores</span></div>\n      <div class=\"profile-stat\"><b id=\"profViews\">0</b><span>Visualiza\u00e7\u00f5es</span></div>\n    </div>\n    <div class=\"profile-actions\">\n      <button class=\"btn follow-btn\" id=\"profFollowBtn\" onclick=\"toggleFollow()\"><span>Seguir</span></button>\n    </div>\n    <div class=\"profile-join\" id=\"profJoin\"></div>\n  </div>\n</div>\n\n<div class=\"toast\" id=\"toast\"><span id=\"toastText\"></span></div>\n\n<script>\n(function(){\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// APP STATE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst APP = { me: null, token: null };\nconst USERS = {}; // cache handle -> {name, handle, avatarUrl, ...}\nlet CHAT_MESSAGES = [];\nlet lastServerTime = null;\nlet chatPollTimer = null;\nlet holdTimer = null;\nconst LETTER_COLORS = ['#ffb020','#ff5d6c','#33c6f4','#3ddc97','#b06cff','#ff8fab','#5ecbe0'];\nlet regAvUrl = null, editAvUrl = null, regSelColor = LETTER_COLORS[0];\nconst ADMIN_PASSWORD = 'liao2026';\nconst EMOJI_LIST = ['\ud83d\ude00','\ud83d\ude02','\ud83e\udd79','\ud83d\ude0d','\ud83d\ude0e','\ud83e\udd29','\ud83e\udd73','\ud83d\ude2d','\ud83d\ude21','\ud83d\udc4d','\ud83d\udc4e','\ud83d\ude4f','\ud83d\udd25','\ud83d\udcaf','\u2764\ufe0f','\ud83d\udc9b','\ud83d\udc99','\ud83d\udc9c','\ud83c\udf89','\u2728','\ud83d\ude31','\ud83e\udd14','\ud83d\ude34','\ud83e\udd1d','\ud83d\udc4f','\ud83d\ude4c','\ud83d\ude05','\ud83e\udee1','\ud83e\udd72','\ud83d\ude24','\ud83e\udef6','\u2b50'];\n\nfunction t(k){ return k; }\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// helpers\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction escapeHtml(s){\n  return (s||'').replace(/[&<>\"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[m]));\n}\nfunction parseMentions(text){\n  return escapeHtml(text).replace(/@([a-zA-Z0-9_]+)/g, (m,h) => `<span class=\"mention\">@${h}</span>`);\n}\nfunction timeAgo(dateStr){\n  const diff = (Date.now() - new Date(dateStr).getTime())/1000;\n  if(diff < 10) return 'agora';\n  if(diff < 60) return Math.floor(diff)+'s';\n  if(diff < 3600) return Math.floor(diff/60)+'m';\n  if(diff < 86400) return Math.floor(diff/3600)+'h';\n  return Math.floor(diff/86400)+'d';\n}\nfunction showToast(msg, isError){\n  const toast = document.getElementById('toast');\n  document.getElementById('toastText').textContent = msg;\n  toast.classList.toggle('err', !!isError);\n  toast.classList.add('show');\n  clearTimeout(toast._t);\n  toast._t = setTimeout(()=> toast.classList.remove('show'), 3000);\n}\nfunction openModal(id){ document.getElementById(id).classList.add('show'); }\nfunction closeModal(id){ document.getElementById(id).classList.remove('show'); }\ndocument.querySelectorAll('.modal-overlay').forEach(m=>{\n  m.addEventListener('click', e=>{ if(e.target===m) m.classList.remove('show'); });\n});\ndocument.addEventListener('keydown', e=>{ if(e.key==='Escape'){ document.querySelectorAll('.modal-overlay.show').forEach(m=>m.classList.remove('show')); } });\n\nfunction avatarInner(u){\n  if(u && u.avatarUrl) return `<img src=\"${u.avatarUrl}\" alt=\"\">`;\n  const letter = ((u && (u.name||u.handle)) || '?').charAt(0).toUpperCase();\n  return letter;\n}\nfunction avatarStyle(u){\n  if(u && u.avatarUrl) return '';\n  return `background:${(u && u.color) || '#7a5fd6'}`;\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// SOCIAL PORTAL LINKS (persisted via localStorage, admin-controlled)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst NETWORKS = {\n  TikTok: { icon:'<svg viewBox=\"0 0 48 48\" fill=\"none\"><path d=\"M31.5 5h6.7c.5 3.3 2.4 6.1 5.3 7.8 1.7 1 3.7 1.6 5.8 1.6v6.9c-3.7 0-7.1-1.2-9.9-3.2v14.6c0 7.5-6.1 13.6-13.6 13.6S12.2 40.2 12.2 32.7c0-7.2 5.6-13.1 12.7-13.6v7.1c-3.1.4-5.5 3-5.5 6.2 0 3.5 2.8 6.3 6.3 6.3s6.3-2.8 6.3-6.3V5h-.5Z\" fill=\"#000\"/><path d=\"M33.2 6.5h6.2c.5 3 2.2 5.6 4.9 7.2 1.6.9 3.4 1.5 5.3 1.5v6.4c-3.4 0-6.6-1.1-9.2-3v13.5c0 7-5.6 12.6-12.6 12.6S15.2 38.1 15.2 31.1c0-6.6 5.2-12.1 11.7-12.6v6.6c-2.8.4-5 2.8-5 5.7 0 3.2 2.6 5.8 5.8 5.8s5.8-2.6 5.8-5.8V6.5Z\" fill=\"#25F4EE\" opacity=\"0.85\"/><path d=\"M29.7 6.5h6.2c.5 3 2.2 5.6 4.9 7.2 1.6.9 3.4 1.5 5.3 1.5v6.4c-3.4 0-6.6-1.1-9.2-3v13.5c0 7-5.6 12.6-12.6 12.6S11.7 38.1 11.7 31.1c0-6.6 5.2-12.1 11.7-12.6v6.6c-2.8.4-5 2.8-5 5.7 0 3.2 2.6 5.8 5.8 5.8s5.8-2.6 5.8-5.8V6.5Z\" fill=\"#FE2C55\" opacity=\"0.85\"/><path d=\"M31.5 6.5h6.2c.5 3 2.2 5.6 4.9 7.2 1.6.9 3.4 1.5 5.3 1.5v6.4c-3.4 0-6.6-1.1-9.2-3v13.5c0 7-5.6 12.6-12.6 12.6S13.5 38.1 13.5 31.1c0-6.6 5.2-12.1 11.7-12.6v6.6c-2.8.4-5 2.8-5 5.7 0 3.2 2.6 5.8 5.8 5.8s5.8-2.6 5.8-5.8V6.5Z\" fill=\"#fff\"/></svg>', color:'#25F4EE' },\n  Instagram: { icon:'<svg viewBox=\"0 0 48 48\"><defs><radialGradient id=\"igGrad\" cx=\"30%\" cy=\"107%\" r=\"150%\"><stop offset=\"0%\" stop-color=\"#FFDD55\"/><stop offset=\"10%\" stop-color=\"#FFDD55\"/><stop offset=\"50%\" stop-color=\"#FF543E\"/><stop offset=\"100%\" stop-color=\"#C837AB\"/></radialGradient></defs><rect x=\"4\" y=\"4\" width=\"40\" height=\"40\" rx=\"11\" fill=\"url(#igGrad)\"/><rect x=\"12\" y=\"12\" width=\"24\" height=\"24\" rx=\"7\" fill=\"none\" stroke=\"#fff\" stroke-width=\"2.6\"/><circle cx=\"24\" cy=\"24\" r=\"6.4\" fill=\"none\" stroke=\"#fff\" stroke-width=\"2.6\"/><circle cx=\"33.2\" cy=\"14.8\" r=\"1.8\" fill=\"#fff\"/></svg>', color:'#DC2777' },\n  YouTube: { icon:'<svg viewBox=\"0 0 48 48\"><rect x=\"3\" y=\"10\" width=\"42\" height=\"28\" rx=\"8\" fill=\"#FF0000\"/><path d=\"M20 17.5v13l11.5-6.5L20 17.5Z\" fill=\"#fff\"/></svg>', color:'#FF0000' },\n  Kwai: { icon:'<svg viewBox=\"0 0 48 48\"><rect x=\"3\" y=\"3\" width=\"42\" height=\"42\" rx=\"10\" fill=\"#FF8A00\"/><path d=\"M24 9c-3 4-3 7.5 0 11.5C27 16.5 27 13 24 9Z\" fill=\"#fff\"/><path d=\"M14 39c2-9 5-14 10-16 5 2 8 7 10 16H14Z\" fill=\"#fff\"/><circle cx=\"24\" cy=\"27\" r=\"4.2\" fill=\"#FF8A00\"/></svg>', color:'#FF8A00' },\n  Facebook: { icon:'<svg viewBox=\"0 0 48 48\"><circle cx=\"24\" cy=\"24\" r=\"21\" fill=\"#1877F2\"/><path d=\"M27 24.5h4l.6-4.6H27v-3c0-1.3.4-2.2 2.3-2.2H32V10.3c-.6-.1-2.1-.2-3.7-.2-3.7 0-6.3 2.3-6.3 6.4v3.4h-4.2v4.6H22V38h5V24.5Z\" fill=\"#fff\"/></svg>', color:'#1877F2' },\n};\nconst NETWORK_ORDER = ['TikTok','Instagram','YouTube','Kwai','Facebook'];\nconst LINKS_KEY = 'liao_social_links_v1';\nfunction loadLinks(){ try{ return JSON.parse(localStorage.getItem(LINKS_KEY)||'{}'); }catch(e){ return {}; } }\nfunction saveLinks(l){ try{ localStorage.setItem(LINKS_KEY, JSON.stringify(l)); return true; }catch(e){ return false; } }\nfunction extractHandle(url){\n  try{ const u=new URL(url); const p=u.pathname.split('/').filter(Boolean); return p.length?'@'+p[p.length-1]:u.hostname; }catch(e){ return url; }\n}\nfunction renderPortals(){\n  const links = loadLinks();\n  const grid = document.getElementById('portalGrid');\n  grid.innerHTML = NETWORK_ORDER.map(net=>{\n    const cfg = NETWORKS[net];\n    const url = links[net];\n    const tag = url ? 'a' : 'div';\n    const attrs = url ? `href=\"${url}\" target=\"_blank\" rel=\"noopener noreferrer\"` : '';\n    return `<${tag} class=\"portal-card${url?'':' empty'}\" ${attrs}>\n      <div class=\"portal-icon-wrap\" style=\"color:${cfg.color}\">${cfg.icon}</div>\n      <div class=\"portal-name\">${net}</div>\n      <div class=\"portal-handle\">${url?extractHandle(url):'em breve'}</div>\n    </${tag}>`;\n  }).join('');\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// ADMIN NOTICE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst NOTICE_KEY = 'liao_admin_notice_v1';\nfunction loadNotice(){ try{ return localStorage.getItem(NOTICE_KEY)||''; }catch(e){ return ''; } }\nfunction saveNotice(txt){ try{ localStorage.setItem(NOTICE_KEY, txt); return true; }catch(e){ return false; } }\nfunction clearNotice(){ try{ localStorage.removeItem(NOTICE_KEY); }catch(e){} }\nfunction renderNotice(){\n  const txt = loadNotice();\n  const el = document.getElementById('adminNotice');\n  if(txt && txt.trim()){\n    el.classList.add('show');\n    document.getElementById('noticeBodyText').textContent = txt;\n  } else {\n    el.classList.remove('show');\n  }\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// AUTH\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction updateRegInit(){\n  const v = document.getElementById('regName').value;\n  const p = document.getElementById('regAvPrev');\n  if(!regAvUrl) p.textContent = v.charAt(0).toUpperCase() || 'C';\n}\nfunction updateEmailPreview(){\n  const v = document.getElementById('regEmail').value.trim();\n  document.getElementById('emailPreview').textContent = v ? v+'@capdrawn.com' : '';\n}\nfunction prevAvatar(inp, prevId){\n  if(!inp.files[0]) return;\n  const r = new FileReader();\n  r.onload = e=>{\n    if(prevId==='regAvPrev') regAvUrl = e.target.result; else editAvUrl = e.target.result;\n    document.getElementById(prevId).innerHTML = `<img src=\"${e.target.result}\">`;\n  };\n  r.readAsDataURL(inp.files[0]);\n}\nfunction buildLetterColorRow(){\n  const row = document.getElementById('regColorRow');\n  row.innerHTML = LETTER_COLORS.map((c,i)=>`<div class=\"letter-dot${i===0?' active':''}\" style=\"background:${c}\" onclick=\"selRegColor('${c}', this)\"></div>`).join('');\n}\nwindow.selRegColor = function(c, el){\n  regSelColor = c;\n  regAvUrl = null;\n  document.getElementById('regAvPrev').style.background = c;\n  document.getElementById('regAvPrev').innerHTML = document.getElementById('regName').value.charAt(0).toUpperCase() || 'C';\n  document.querySelectorAll('.letter-dot').forEach(d=>d.classList.remove('active'));\n  el.classList.add('active');\n};\n\nfunction openLogin(){ openModal('loginModal'); }\nfunction openRegister(){ closeModal('loginModal'); openModal('regModal'); }\n\nfunction createAccount(){\n  const name = document.getElementById('regName').value.trim();\n  const handle = document.getElementById('regHandle').value.trim().replace(/[^a-z0-9_]/gi,'').toLowerCase();\n  const emailRaw = document.getElementById('regEmail').value.trim();\n  const password = document.getElementById('regPass').value;\n  const errEl = document.getElementById('regErr');\n  errEl.classList.remove('show');\n  if(!name || !handle){ errEl.textContent='Preencha nome e usu\u00e1rio.'; errEl.classList.add('show'); return; }\n  if(!emailRaw){ errEl.textContent='Preencha o email.'; errEl.classList.add('show'); return; }\n  if(!password || password.length<6){ errEl.textContent='Senha deve ter ao menos 6 caracteres.'; errEl.classList.add('show'); return; }\n\n  const btn = document.getElementById('regBtn');\n  btn.disabled = true; btn.textContent = 'Criando...';\n  fetch('/api/auth/register', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ name, handle, email: emailRaw, password }) })\n    .then(r=>r.json()).then(data=>{\n      btn.disabled = false; btn.textContent = 'Criar conta';\n      if(!data.ok){ errEl.textContent = data.error; errEl.classList.add('show'); return; }\n      APP.token = data.token;\n      const u = data.user;\n      APP.me = { ...u, color: regAvUrl ? null : regSelColor };\n      USERS[u.handle] = APP.me;\n      localStorage.setItem('cdToken', data.token);\n      localStorage.setItem('cdLoggedIn', u.handle);\n      localStorage.setItem('cdColor:'+u.handle, APP.me.color || '');\n      regAvUrl = null;\n      closeModal('regModal');\n      onLoggedIn();\n      showToast('Conta criada! Bem-vindo, '+u.name+'.');\n    }).catch(()=>{ btn.disabled=false; btn.textContent='Criar conta'; showToast('Erro de conex\u00e3o.', true); });\n}\n\nfunction doLogin(){\n  const emailRaw = document.getElementById('liEmail').value.trim();\n  const password = document.getElementById('liPass').value;\n  const errEl = document.getElementById('loginErr');\n  errEl.classList.remove('show');\n  if(!emailRaw || !password){ showToast('Preencha email e senha.', true); return; }\n  const btn = document.getElementById('loginBtn');\n  btn.disabled = true; btn.textContent = 'Entrando...';\n  fetch('/api/auth/login', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ email: emailRaw, password }) })\n    .then(r=>r.json()).then(data=>{\n      btn.disabled = false; btn.textContent = 'Entrar';\n      if(!data.ok){ errEl.textContent = data.error; errEl.classList.add('show'); return; }\n      APP.token = data.token;\n      const u = data.user;\n      const savedColor = localStorage.getItem('cdColor:'+u.handle) || LETTER_COLORS[0];\n      APP.me = { ...u, color: savedColor };\n      USERS[u.handle] = APP.me;\n      localStorage.setItem('cdToken', data.token);\n      localStorage.setItem('cdLoggedIn', u.handle);\n      closeModal('loginModal');\n      onLoggedIn();\n      showToast('Bem-vindo de volta, '+u.name+'.');\n    }).catch(()=>{ btn.disabled=false; btn.textContent='Entrar'; showToast('Erro de conex\u00e3o.', true); });\n}\n\nfunction onLoggedIn(){\n  const u = APP.me;\n  document.getElementById('btnLogin').style.display = 'none';\n  document.getElementById('btnReg').style.display = 'none';\n  const nav = document.getElementById('navAv');\n  nav.style.display = 'flex';\n  nav.style.background = avatarStyle(u).replace('background:','') || '#7a5fd6';\n  nav.innerHTML = avatarInner(u);\n  document.getElementById('loginPromptChat').style.display = 'none';\n  document.getElementById('chatCompose').style.display = 'block';\n  const cav = document.getElementById('composeAv');\n  cav.style.background = avatarStyle(u).replace('background:','') || '#7a5fd6';\n  cav.innerHTML = avatarInner(u);\n  renderChat();\n}\n\nfunction logout(){\n  APP.me = null; APP.token = null;\n  document.getElementById('btnLogin').style.display = '';\n  document.getElementById('btnReg').style.display = '';\n  document.getElementById('navAv').style.display = 'none';\n  document.getElementById('loginPromptChat').style.display = 'flex';\n  document.getElementById('chatCompose').style.display = 'none';\n  localStorage.removeItem('cdToken'); localStorage.removeItem('cdLoggedIn');\n  document.getElementById('avMenu').classList.remove('open');\n  renderChat();\n  showToast('Voc\u00ea saiu da conta.');\n}\n\nfunction toggleAvMenu(e){ e.stopPropagation(); if(!APP.me){ openLogin(); return; } document.getElementById('avMenu').classList.toggle('open'); }\ndocument.addEventListener('click', ()=> document.getElementById('avMenu').classList.remove('open'));\n\nfunction openEditProfileModal(){\n  if(!APP.me){ openLogin(); return; }\n  const u = APP.me;\n  document.getElementById('editName').value = u.name;\n  document.getElementById('editDesc').value = u.bio || '';\n  const p = document.getElementById('editAvPrev');\n  p.style.background = avatarStyle(u).replace('background:','') || '#7a5fd6';\n  p.innerHTML = avatarInner(u);\n  openModal('editModal');\n}\n\nasync function saveProfile(){\n  if(!APP.me) return;\n  const name = document.getElementById('editName').value.trim() || APP.me.name;\n  const desc = document.getElementById('editDesc').value.trim();\n  try{\n    const putRes = await fetch('/api/users/'+APP.me.handle, {\n      method:'PUT', headers:{'Content-Type':'application/json','Authorization':'Bearer '+APP.token},\n      body: JSON.stringify({ name, desc })\n    });\n    const putData = await putRes.json();\n    if(!putData.ok){ showToast('Erro ao salvar: '+putData.error, true); return; }\n    APP.me.name = name; APP.me.bio = desc;\n    if(editAvUrl){\n      const avRes = await fetch('/api/auth/avatar', {\n        method:'POST', headers:{'Content-Type':'application/json','Authorization':'Bearer '+APP.token},\n        body: JSON.stringify({ avatarBase64: editAvUrl, name, bio: desc })\n      });\n      const avData = await avRes.json();\n      if(avData.ok && avData.user?.avatarUrl) APP.me.avatarUrl = avData.user.avatarUrl;\n    }\n    editAvUrl = null;\n    closeModal('editModal');\n    onLoggedIn();\n    showToast('Perfil atualizado!');\n  }catch(e){ showToast('Erro ao salvar perfil.', true); }\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CHAT GLOBAL \u2014 polling em tempo real + GIFs + rea\u00e7\u00f5es\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction authHeaders(){\n  return APP.token ? { 'Authorization': 'Bearer '+APP.token } : {};\n}\n\nasync function loadChatInitial(){\n  try{\n    const res = await fetch('/api/comments?videoId=home', { headers: authHeaders() });\n    const data = await res.json();\n    if(data.ok){\n      CHAT_MESSAGES = data.comments;\n      lastServerTime = data.serverTime;\n      data.comments.forEach(c => { USERS[c.user.handle] = { ...(USERS[c.user.handle]||{}), ...c.user }; });\n      renderChat();\n    }\n  }catch(e){ /* silencioso */ }\n  startChatPolling();\n}\n\nfunction startChatPolling(){\n  clearInterval(chatPollTimer);\n  chatPollTimer = setInterval(pollChat, 3000);\n}\n\nasync function pollChat(){\n  if(!lastServerTime) return;\n  try{\n    const res = await fetch('/api/comments?videoId=home&since='+encodeURIComponent(lastServerTime), { headers: authHeaders() });\n    const data = await res.json();\n    if(data.ok && data.comments.length){\n      data.comments.forEach(c => {\n        if(!CHAT_MESSAGES.find(x=>x.id===c.id)){\n          CHAT_MESSAGES.push(c);\n          USERS[c.user.handle] = { ...(USERS[c.user.handle]||{}), ...c.user };\n        }\n      });\n      lastServerTime = data.serverTime;\n      renderChat();\n    } else if(data.ok){\n      lastServerTime = data.serverTime;\n    }\n  }catch(e){ /* silencioso */ }\n}\n\nfunction renderChat(){\n  const list = document.getElementById('chatList');\n  document.getElementById('chatCount').textContent = CHAT_MESSAGES.length + ' mensagens';\n  if(!CHAT_MESSAGES.length){\n    list.innerHTML = '<div class=\"chat-empty\">Seja o primeiro a comentar no chat!</div>';\n    return;\n  }\n  const wasNearBottom = (list.scrollTop + list.clientHeight) >= (list.scrollHeight - 60);\n  list.innerHTML = CHAT_MESSAGES.map(c => renderMsg(c)).join('');\n  if(wasNearBottom) list.scrollTop = list.scrollHeight;\n}\n\nfunction renderMsg(c){\n  const u = c.user;\n  const av = avatarInner(u);\n  const st = avatarStyle(u);\n  const verBadge = u.isVerified ? `<span class=\"msg-verified\"><svg viewBox=\"0 0 24 24\" fill=\"white\"><path d=\"M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z\"/></svg></span>` : '';\n  const vipBadge = u.isVip ? `<span class=\"msg-vip\">VIP</span>` : '';\n  const gif = c.gifUrl ? `<div class=\"msg-gif\"><img src=\"${c.gifUrl}\" loading=\"lazy\" alt=\"gif\"></div>` : '';\n  const reactions = Object.values(c.reactions||{});\n  const reactHtml = reactions.length ? `<div class=\"msg-reactions\">${reactions.map(r=>`<div class=\"reaction-pill${r.byMe?' mine':''}\" onclick=\"toggleReaction('${c.id}','${r.emoji}')\">${r.emoji}<span class=\"rc-count\">${r.count}</span></div>`).join('')}</div>` : '';\n  return `<div class=\"msg\" data-id=\"${c.id}\"\n      onpointerdown=\"startHold(event,'${c.id}')\" onpointerup=\"cancelHold()\" onpointerleave=\"cancelHold()\" onpointercancel=\"cancelHold()\">\n    <div class=\"msg-av\" style=\"${st}\" onclick=\"openProfile('${u.handle}')\">${av}</div>\n    <div class=\"msg-body\">\n      <div class=\"msg-top\">\n        <span class=\"msg-name\" onclick=\"openProfile('${u.handle}')\">${escapeHtml(u.name)}</span>${verBadge}${vipBadge}\n        <span class=\"msg-time\">${timeAgo(c.createdAt)}</span>\n      </div>\n      ${c.text ? `<div class=\"msg-text\">${parseMentions(c.text)}</div>` : ''}\n      ${gif}\n      ${reactHtml}\n      <div class=\"react-popover\" id=\"rp-${c.id}\">\n        ${['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\udc4d','\ud83d\udd25'].map(e=>`<button class=\"react-emoji\" onclick=\"toggleReaction('${c.id}','${e}');closeAllReactPopovers()\">${e}</button>`).join('')}\n      </div>\n    </div>\n  </div>`;\n}\n\nfunction startHold(ev, id){\n  if(!APP.me) return;\n  cancelHold();\n  holdTimer = setTimeout(()=>{\n    closeAllReactPopovers();\n    const pop = document.getElementById('rp-'+id);\n    if(pop) pop.classList.add('show');\n  }, 420);\n}\nfunction cancelHold(){ clearTimeout(holdTimer); }\nfunction closeAllReactPopovers(){ document.querySelectorAll('.react-popover.show').forEach(p=>p.classList.remove('show')); }\ndocument.addEventListener('click', (e)=>{ if(!e.target.closest('.msg')) closeAllReactPopovers(); });\n\nasync function toggleReaction(commentId, emoji){\n  if(!APP.me){ openLogin(); return; }\n  const c = CHAT_MESSAGES.find(x=>x.id===commentId);\n  if(c){\n    c.reactions = c.reactions || {};\n    const r = c.reactions[emoji];\n    if(r && r.byMe){ r.count--; r.byMe=false; if(r.count<=0) delete c.reactions[emoji]; }\n    else{ c.reactions[emoji] = c.reactions[emoji] || {emoji, count:0, byMe:false}; c.reactions[emoji].count++; c.reactions[emoji].byMe=true; }\n    renderChat();\n  }\n  try{\n    await fetch('/api/comment-react', { method:'POST', headers:{'Content-Type':'application/json', ...authHeaders()}, body: JSON.stringify({ commentId, emoji }) });\n  }catch(e){}\n}\n\nasync function sendChatMessage(gifUrl){\n  if(!APP.me){ openLogin(); return; }\n  const inp = document.getElementById('chatInput');\n  const text = (inp.value||'').trim();\n  if(!text && !gifUrl) return;\n  const sendBtn = document.getElementById('chatSendBtn');\n  sendBtn.disabled = true;\n  try{\n    const res = await fetch('/api/comments', {\n      method:'POST', headers:{'Content-Type':'application/json', ...authHeaders()},\n      body: JSON.stringify({ text, gifUrl: gifUrl||null })\n    });\n    const data = await res.json();\n    if(data.ok){\n      CHAT_MESSAGES.push(data.comment);\n      lastServerTime = data.comment.createdAt;\n      inp.value = '';\n      hideMentionDrop();\n      renderChat();\n      document.getElementById('chatList').scrollTop = 999999;\n    } else {\n      showToast(data.error || 'Erro ao enviar mensagem.', true);\n    }\n  }catch(e){ showToast('Erro de conex\u00e3o.', true); }\n  sendBtn.disabled = false;\n}\n\nfunction onChatKey(e){ if(e.key==='Enter' && !e.shiftKey){ e.preventDefault(); sendChatMessage(); } }\n\nfunction onChatInput(el){\n  const v = el.value, la = v.lastIndexOf('@');\n  if(la===-1){ hideMentionDrop(); return; }\n  const q = v.slice(la+1).toLowerCase();\n  if(!q){ hideMentionDrop(); return; }\n  const matches = Object.values(USERS).filter(u => u.handle?.toLowerCase().startsWith(q) || u.name?.toLowerCase().startsWith(q)).slice(0,6);\n  if(!matches.length){ hideMentionDrop(); return; }\n  const drop = document.getElementById('mentionDrop');\n  drop.innerHTML = matches.map(u=>`<div class=\"mention-item\" onclick=\"completeMention('${u.handle}')\">\n    <div class=\"mi-av\" style=\"${avatarStyle(u)}\">${avatarInner(u)}</div>\n    <div><strong style=\"font-size:.8rem;\">${escapeHtml(u.name)}</strong><div style=\"font-size:.68rem;color:var(--ink-3);\">@${u.handle}</div></div>\n  </div>`).join('');\n  drop.classList.add('show');\n}\nfunction completeMention(h){\n  const inp = document.getElementById('chatInput'), v = inp.value, la = v.lastIndexOf('@');\n  inp.value = v.slice(0,la+1)+h+' ';\n  hideMentionDrop();\n  inp.focus();\n}\nfunction hideMentionDrop(){ document.getElementById('mentionDrop').classList.remove('show'); }\n\n// Emoji picker\nfunction buildEmojiPicker(){\n  document.getElementById('emojiPicker').innerHTML = EMOJI_LIST.map(e=>`<button onclick=\"insertEmoji('${e}')\">${e}</button>`).join('');\n}\nfunction insertEmoji(e){\n  const inp = document.getElementById('chatInput');\n  inp.value += e;\n  inp.focus();\n}\nfunction toggleEmojiPicker(){\n  document.getElementById('gifPicker').classList.remove('show');\n  document.getElementById('emojiPicker').classList.toggle('show');\n}\n\n// GIF picker (Tenor via proxy)\nlet gifSearchDebounce = null;\nfunction toggleGifPicker(){\n  document.getElementById('emojiPicker').classList.remove('show');\n  const p = document.getElementById('gifPicker');\n  p.classList.toggle('show');\n  if(p.classList.contains('show') && !p._loaded){ p._loaded = true; searchGifs(''); }\n}\nfunction onGifSearch(q){\n  clearTimeout(gifSearchDebounce);\n  gifSearchDebounce = setTimeout(()=> searchGifs(q), 350);\n}\nasync function searchGifs(q){\n  const grid = document.getElementById('gifGrid');\n  grid.innerHTML = '<div class=\"gif-empty\">Buscando...</div>';\n  try{\n    const res = await fetch('/api/gifs?q='+encodeURIComponent(q));\n    const data = await res.json();\n    if(!data.ok || !data.gifs.length){ grid.innerHTML = '<div class=\"gif-empty\">Nenhum GIF encontrado.</div>'; return; }\n    grid.innerHTML = data.gifs.map(g=>`<img src=\"${g.preview}\" onclick=\"pickGif('${g.url}')\" loading=\"lazy\">`).join('');\n  }catch(e){ grid.innerHTML = '<div class=\"gif-empty\">Erro ao buscar GIFs.</div>'; }\n}\nfunction pickGif(url){\n  document.getElementById('gifPicker').classList.remove('show');\n  sendChatMessage(url);\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// PROFILE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet viewingHandle = null;\nasync function openProfile(handle){\n  viewingHandle = handle;\n  try{\n    const res = await fetch('/api/users/'+handle);\n    const data = await res.json();\n    if(!data.ok){ showToast('Perfil n\u00e3o encontrado.', true); return; }\n    const u = data.user;\n    document.getElementById('profAvatarBig').style.background = avatarStyle(u).replace('background:','') || '#7a5fd6';\n    document.getElementById('profAvatarBig').innerHTML = avatarInner(u);\n    document.getElementById('profName').innerHTML = escapeHtml(u.name) + (u.isVerified ? ' <span class=\"msg-verified\" style=\"width:16px;height:16px;\"><svg viewBox=\"0 0 24 24\" fill=\"white\" width=\"10\" height=\"10\"><path d=\"M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z\"/></svg></span>' : '');\n    document.getElementById('profHandle').textContent = '@'+u.handle;\n    document.getElementById('profBio').textContent = u.bio || '';\n    document.getElementById('profFollowers').textContent = u.followers || 0;\n    document.getElementById('profViews').textContent = u.totalViews || 0;\n    const joinDate = new Date(u.createdAt);\n    document.getElementById('profJoin').textContent = 'Membro desde ' + joinDate.toLocaleDateString('pt-BR', {day:'2-digit', month:'long', year:'numeric'});\n    updateFollowButton(u.handle);\n    document.getElementById('profilePage').classList.add('show');\n    document.body.style.overflow = 'hidden';\n  }catch(e){ showToast('Erro ao carregar perfil.', true); }\n}\nfunction openProfileSelf(){ if(!APP.me){ openLogin(); return; } openProfile(APP.me.handle); }\nfunction closeProfile(){ document.getElementById('profilePage').classList.remove('show'); document.body.style.overflow=''; viewingHandle=null; }\n\nfunction followKey(h){ return 'liao_following_'+h; }\nfunction isFollowing(h){ return localStorage.getItem(followKey(h)) === '1'; }\nfunction updateFollowButton(handle){\n  const btn = document.getElementById('profFollowBtn');\n  const following = isFollowing(handle);\n  btn.classList.toggle('following', following);\n  btn.querySelector('span').textContent = following ? 'Seguindo' : 'Seguir';\n}\nfunction toggleFollow(){\n  if(!APP.me){ openLogin(); return; }\n  if(!viewingHandle) return;\n  const following = !isFollowing(viewingHandle);\n  localStorage.setItem(followKey(viewingHandle), following ? '1':'0');\n  updateFollowButton(viewingHandle);\n  const el = document.getElementById('profFollowers');\n  const cur = parseInt(el.textContent,10)||0;\n  el.textContent = following ? cur+1 : Math.max(0,cur-1);\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// ADMIN MODAL\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction openAdminModal(){\n  const lock = document.getElementById('adminLockBody');\n  const panel = document.getElementById('adminPanelBody');\n  lock.style.display = 'block'; panel.style.display = 'none';\n  document.getElementById('adminPasswordInput').value = '';\n  document.getElementById('adminError').classList.remove('show');\n  openModal('adminModal');\n  setTimeout(()=> document.getElementById('adminPasswordInput').focus(), 150);\n}\nfunction tryUnlockAdmin(){\n  const val = document.getElementById('adminPasswordInput').value.trim();\n  if(val === ADMIN_PASSWORD){\n    document.getElementById('adminLockBody').style.display = 'none';\n    document.getElementById('adminPanelBody').style.display = 'block';\n    document.getElementById('adminError').classList.remove('show');\n    renderAdminLinkRows();\n  } else {\n    document.getElementById('adminError').classList.add('show');\n  }\n}\nfunction renderAdminLinkRows(){\n  const links = loadLinks();\n  const list = document.getElementById('linkRowList');\n  const entries = Object.entries(links);\n  if(!entries.length){ list.innerHTML = '<div style=\"font-size:12px;color:var(--ink-3);text-align:center;padding:8px 0;\">Nenhum link cadastrado ainda.</div>'; return; }\n  list.innerHTML = entries.map(([net,url])=>`<div class=\"link-row\">\n    <span class=\"lr-net\">${net}</span><span class=\"lr-url\">${url}</span>\n    <button class=\"lr-del\" data-net=\"${net}\">\u2715</button>\n  </div>`).join('');\n  list.querySelectorAll('.lr-del').forEach(btn=>{\n    btn.addEventListener('click', ()=>{\n      const links = loadLinks();\n      delete links[btn.dataset.net];\n      saveLinks(links);\n      renderAdminLinkRows();\n      renderPortals();\n      showToast('Link de '+btn.dataset.net+' removido.');\n    });\n  });\n}\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// INIT\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction init(){\n  buildLetterColorRow();\n  buildEmojiPicker();\n  renderPortals();\n  renderNotice();\n\n  document.getElementById('adminSubmitBtn').addEventListener('click', tryUnlockAdmin);\n  document.getElementById('adminPasswordInput').addEventListener('keydown', e=>{ if(e.key==='Enter') tryUnlockAdmin(); });\n  document.getElementById('addLinkBtn').addEventListener('click', ()=>{\n    const net = document.getElementById('newLinkNetwork').value;\n    let url = document.getElementById('newLinkUrl').value.trim();\n    if(!url){ showToast('Cole um link.', true); return; }\n    if(!/^https?:\\/\\//i.test(url)) url = 'https://'+url;\n    try{ new URL(url); }catch(e){ showToast('Link inv\u00e1lido.', true); return; }\n    const links = loadLinks();\n    links[net] = url;\n    saveLinks(links);\n    document.getElementById('newLinkUrl').value = '';\n    renderAdminLinkRows();\n    renderPortals();\n    showToast('Link de '+net+' atualizado.');\n  });\n  document.getElementById('adminTabLinks').addEventListener('click', ()=> switchAdminTab('links'));\n  document.getElementById('adminTabNotice').addEventListener('click', ()=> switchAdminTab('notice'));\n  document.getElementById('publishNoticeBtn').addEventListener('click', ()=>{\n    const txt = document.getElementById('noticeTextarea').value.trim();\n    if(!txt){ showToast('Escreva uma mensagem.', true); return; }\n    saveNotice(txt); renderNotice(); showToast('Aviso publicado!');\n  });\n  document.getElementById('clearNoticeBtn').addEventListener('click', ()=>{\n    clearNotice(); document.getElementById('noticeTextarea').value=''; renderNotice(); showToast('Aviso removido.');\n  });\n\n  // restore session\n  const savedToken = localStorage.getItem('cdToken');\n  const savedHandle = localStorage.getItem('cdLoggedIn');\n  if(savedToken && savedHandle){\n    APP.token = savedToken;\n    fetch('/api/users/'+savedHandle).then(r=>r.json()).then(data=>{\n      if(data.ok){\n        const savedColor = localStorage.getItem('cdColor:'+savedHandle) || LETTER_COLORS[0];\n        APP.me = { ...data.user, color: savedColor };\n        USERS[savedHandle] = APP.me;\n        onLoggedIn();\n      } else {\n        document.getElementById('loginPromptChat').style.display = 'flex';\n      }\n    }).catch(()=>{ document.getElementById('loginPromptChat').style.display = 'flex'; });\n  } else {\n    document.getElementById('loginPromptChat').style.display = 'flex';\n  }\n\n  loadChatInitial();\n}\nfunction switchAdminTab(which){\n  const isLinks = which==='links';\n  document.getElementById('adminTabLinks').classList.toggle('active', isLinks);\n  document.getElementById('adminTabNotice').classList.toggle('active', !isLinks);\n  document.getElementById('adminPanelLinks').classList.toggle('show', isLinks);\n  document.getElementById('adminPanelNotice').classList.toggle('show', !isLinks);\n  if(!isLinks) document.getElementById('noticeTextarea').value = loadNotice();\n}\n\n// expose to global scope for inline handlers\nwindow.openLogin=openLogin; window.openRegister=openRegister; window.createAccount=createAccount; window.doLogin=doLogin;\nwindow.logout=logout; window.toggleAvMenu=toggleAvMenu; window.openProfileSelf=openProfileSelf; window.openEditProfileModal=openEditProfileModal;\nwindow.saveProfile=saveProfile; window.closeModal=closeModal; window.updateRegInit=updateRegInit; window.updateEmailPreview=updateEmailPreview;\nwindow.prevAvatar=prevAvatar; window.sendChatMessage=sendChatMessage; window.onChatKey=onChatKey; window.onChatInput=onChatInput;\nwindow.completeMention=completeMention; window.toggleEmojiPicker=toggleEmojiPicker; window.insertEmoji=insertEmoji;\nwindow.toggleGifPicker=toggleGifPicker; window.onGifSearch=onGifSearch; window.pickGif=pickGif; window.toggleReaction=toggleReaction;\nwindow.startHold=startHold; window.cancelHold=cancelHold; window.openProfile=openProfile; window.closeProfile=closeProfile;\nwindow.toggleFollow=toggleFollow; window.openAdminModal=openAdminModal;\n\ninit();\n})();\n</script>\n\n</body>\n</html>\n";

export default HTML;
